import sys

RADIX = 255
OFF1 = 5
OFF2 = 2
INTOFF = 9
LITSIZE = 4

class RangeEncoder:
    def __init__(self):
        self.cc = [0, 0] * 1000000
        self.range = 1
        self.fraction = 0
        self.out = bytearray()

    def emit_byte(self, digit):
        self.out.append((digit + 1) & 0xFF)

    def normalize_encoder(self):
        while self.range < RADIX:
            digit = self.fraction // RADIX
            self.fraction = (self.fraction - digit * RADIX) * RADIX
            self.range *= RADIX
            self.emit_byte(digit)

    def put_bit(self, ctx, bit):
        self.normalize_encoder()
        idx = ctx * 2
        c0 = self.cc[idx]
        c1 = self.cc[idx + 1]
        split = self.range * (c0 + 1) // (c0 + c1 + 2)
        if bit == 0:
            self.range = split
        else:
            self.fraction += split
            self.range -= split
        self.cc[idx + bit] += 1

    def encode_integer(self, start, ctx, value):
        result = value + (1 << start)
        k = result.bit_length() - 1
        tmp = start
        ctx2 = ctx * 99
        for _ in range(k):
            tmp += 1
            self.put_bit(tmp + ctx2, 0)
        tmp += 1
        self.put_bit(tmp + ctx2, 1)
        for i in range(k - 1, -1, -1):
            self.put_bit(ctx2, (result >> i) & 1)

    def finish(self):
        self.normalize_encoder()
        for _ in range(8):
            self.emit_byte(0)

def parse(data):
    n = len(data)
    tokens = []
    i = 0
    while i < n:
        best_len = 0
        best_off = 0
        max_off = min(i, 1 << OFF1)
        max_len = 1 << 12
        for off in range(1, max_off + 1):
            l = 0
            while i + l < n and l < max_len and data[i + l] == data[i - off + l]:
                l += 1
            if l > best_len:
                best_len = l
                best_off = off
        if best_len >= 4:
            tokens.append(('M', best_off, best_len))
            i += best_len
        else:
            tokens.append(('L', data[i]))
            i += 1
    return tokens

def encode(tokens, total):
    enc = RangeEncoder()
    enc.encode_integer(INTOFF, 0, total)
    for tok in tokens:
        if tok[0] == 'M':
            enc.put_bit(1, 1)
            enc.encode_integer(OFF1, 2, tok[1] - 1)
            enc.encode_integer(OFF2, 3, tok[2] - 1)
        else:
            b = tok[1]
            enc.put_bit(1, 0)
            if b < 128:
                enc.put_bit(8, 0)
                enc.encode_integer(LITSIZE, 9, b)
            else:
                enc.put_bit(8, 1)
                enc.encode_integer(LITSIZE, 9, 256 - b)
    enc.finish()
    return bytes(enc.out)

def main():
    data = open('/app/data.txt', 'rb').read()
    tokens = parse(data)
    comp = encode(tokens, len(data))
    with open('/app/data.comp', 'wb') as f:
        f.write(comp)
    print('tokens', len(tokens), 'comp_size', len(comp))
    if len(comp) > 2500:
        print('TOO_BIG')

main()
